1	// claim-office.ts
2	
3	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
4	type Item = {
5	  type: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
6	  material?: string;
7	  enchantment?: number;
8	  cursed?: boolean;
9	};
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	const RUNE_BLOCK_SIZE = 3;
14	const RUNE_BLOCK_PRICE = 60;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	};
23	
24	export function quote(_customer: Customer, items: Item[]): number {
25	  const runeCount = items.filter((i) => i.type === "rune").length;
26	  const itemsBase = runeCount === RUNE_BLOCK_SIZE
27	    ? RUNE_BLOCK_PRICE
28	    : items.reduce((total, item) => total + BASE_PREMIUMS[item.type], 0);
29	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
30	  return itemsBase + firstInsurance + PROCESSING_FEE;
31	}
